//! Five-level dyadic **image** structure (luma band energies) plus cheap monocular **depth cue**
//! proxies inspired by Gibsonian cues: texture gradient, aerial perspective, linear-perspective
//! edge anisotropy, and occlusion boundaries.
//!
//! This is **not** the same subsystem as [`crate::standing_wave_pinning`] (Q/K/V attention
//! standing dimensions on transformer hidden states). Here “levels” mean **spatial scales** on
//! RGB, analogous to how humans multiplex coarse vs fine evidence—not a claim that attention
//! waves literally equal monocular depth.
//!
//! **Relative size / metric depth:** monocular stacks remain **ratio-scale** without anchors.
//! [`MonocularCueProvenance::scale_ambiguity`] records that explicit gap; host layers can supply
//! focal length + known object extent later as an additional sieve view.
//!
//! **Perf:** On native targets, multi-scale box means and Sobel use Rayon parallelism; WASM builds
//! stay single-thread. Scale 0 aliases luma (`copy_from_slice`), avoiding redundant integral queries.

use serde::{Deserialize, Serialize};

#[cfg(not(target_arch = "wasm32"))]
use gnosis_frf::prelude::*;

use crate::depth_extrusion::DepthError;

/// Number of dyadic smoothing levels (fine → coarse) used for band energies.
pub const MONOCULAR_CUE_LEVELS: usize = 5;

/// Half-radii for centered box means: 1×1, 3×3, 5×5, 9×9, 17×17 (inclusive windows).
const LEVEL_HALVES: [usize; MONOCULAR_CUE_LEVELS] = [0, 1, 2, 4, 8];

#[derive(Clone, Debug, Serialize, Deserialize, PartialEq)]
pub struct MonocularCueProvenance {
    /// Mean per-pixel band energy `|M_s - M_{s+1}|` (last entry: mean of `M_4`).
    pub level_band_energy_mean: [f32; MONOCULAR_CUE_LEVELS],
    /// Explicit statement that output is unanchored in meters unless a host supplies scale priors.
    pub scale_ambiguity: String,
}

#[derive(Clone, Debug)]
pub struct MonocularCueMaps {
    /// Single fused cue plane in `[0,1]` for optional blending into mesh depth.
    pub cue_prior: Vec<f32>,
    pub provenance: MonocularCueProvenance,
}

#[inline]
fn luma_at(rgb: &[f32], i: usize) -> f32 {
    let o = i * 3;
    let r = rgb[o].clamp(0.0, 1.0);
    let g = rgb[o + 1].clamp(0.0, 1.0);
    let b = rgb[o + 2].clamp(0.0, 1.0);
    (0.2126 * r + 0.7152 * g + 0.0722 * b).clamp(0.0, 1.0)
}

fn luma_seq(rgb: &[f32], w: usize, h: usize) -> Result<Vec<f32>, DepthError> {
    let n = w
        .checked_mul(h)
        .ok_or(DepthError::Shape)?
        .checked_mul(3)
        .ok_or(DepthError::Shape)?;
    if rgb.len() != n {
        return Err(DepthError::Shape);
    }
    let mut out = Vec::with_capacity(w * h);
    for i in 0..w * h {
        out.push(luma_at(rgb, i));
    }
    Ok(out)
}

/// Exclusive-end integral: `ii[(y+1)*(w+1)+(x+1)]` = sum of `luma[0..=y][0..=x]`.
fn integral_image(luma: &[f32], w: usize, h: usize) -> Vec<f64> {
    let row = w + 1;
    let mut ii = vec![0.0_f64; row * (h + 1)];
    for y in 0..h {
        let y0 = y * row;
        let y1 = (y + 1) * row;
        let ly = y * w;
        for x in 0..w {
            let v = luma[ly + x] as f64;
            let idx = y1 + x + 1;
            ii[idx] = v + ii[y0 + x + 1] + ii[y1 + x] - ii[y0 + x];
        }
    }
    ii
}

#[inline]
fn rect_sum(ii: &[f64], w: usize, x0: usize, y0: usize, x1: usize, y1: usize) -> f64 {
    // (x0,y0) inclusive top-left, (x1,y1) exclusive bottom-right in luma coords
    let r = w + 1;
    ii[y1 * r + x1] - ii[y0 * r + x1] - ii[y1 * r + x0] + ii[y0 * r + x0]
}

fn centered_box_mean(ii: &[f64], w: usize, h: usize, x: usize, y: usize, half: usize) -> f32 {
    let (x0, y0, x1, y1) = if half == 0 {
        (x, y, x + 1, y + 1)
    } else {
        let x0 = x.saturating_sub(half);
        let y0 = y.saturating_sub(half);
        let x1 = (x + half + 1).min(w);
        let y1 = (y + half + 1).min(h);
        (x0, y0, x1, y1)
    };
    let area = ((x1 - x0) * (y1 - y0)).max(1) as f64;
    (rect_sum(ii, w, x0, y0, x1, y1) / area) as f32
}

fn fill_level_means(dst: &mut [f32], ii: &[f64], w: usize, h: usize, half: usize) {
    let img_w = w;
    #[cfg(not(target_arch = "wasm32"))]
    {
        dst.par_chunks_mut(w).enumerate().for_each(|(y, row)| {
            for (x, cell) in row.iter_mut().enumerate() {
                *cell = centered_box_mean(ii, img_w, h, x, y, half);
            }
        });
    }
    #[cfg(target_arch = "wasm32")]
    {
        for y in 0..h {
            for x in 0..w {
                dst[y * w + x] = centered_box_mean(ii, img_w, h, x, y, half);
            }
        }
    }
}

fn means_per_level(
    luma: &[f32],
    w: usize,
    h: usize,
) -> Result<[Vec<f32>; MONOCULAR_CUE_LEVELS], DepthError> {
    let n = w.checked_mul(h).ok_or(DepthError::Shape)?;
    if luma.len() != n {
        return Err(DepthError::Shape);
    }
    let ii = integral_image(luma, w, h);
    let mut out: [Vec<f32>; MONOCULAR_CUE_LEVELS] = std::array::from_fn(|_| vec![0.0_f32; n]);
    out[0].copy_from_slice(luma);

    for s in 1..MONOCULAR_CUE_LEVELS {
        let half = LEVEL_HALVES[s];
        fill_level_means(&mut out[s], &ii, w, h, half);
    }
    Ok(out)
}

#[inline]
fn sobel_xy_at(luma: &[f32], w: usize, h: usize, x: usize, y: usize) -> (f32, f32) {
    let wi = w as i32;
    let hi = h as i32;
    let xi = x as i32;
    let yi = y as i32;
    let samp = |dx: i32, dy: i32| -> f32 {
        let nx = (xi + dx).clamp(0, wi - 1) as usize;
        let ny = (yi + dy).clamp(0, hi - 1) as usize;
        luma[ny * w + nx]
    };
    let gxv = -samp(-1, -1) + 1.0 * samp(1, -1) - 2.0 * samp(-1, 0) + 2.0 * samp(1, 0)
        - 1.0 * samp(-1, 1)
        + 1.0 * samp(1, 1);
    let gyv = -samp(-1, -1) - 2.0 * samp(0, -1) - 1.0 * samp(1, -1)
        + 1.0 * samp(-1, 1)
        + 2.0 * samp(0, 1)
        + 1.0 * samp(1, 1);
    (gxv, gyv)
}

fn sobel_luma_mag(luma: &[f32], w: usize, h: usize) -> (Vec<f32>, Vec<f32>, Vec<f32>) {
    let n = w * h;
    let mut gx = vec![0.0_f32; n];
    let mut gy = vec![0.0_f32; n];
    let mut mag = vec![0.0_f32; n];

    #[cfg(not(target_arch = "wasm32"))]
    {
        gx.par_chunks_mut(w)
            .zip(gy.par_chunks_mut(w))
            .zip(mag.par_chunks_mut(w))
            .enumerate()
            .for_each(|(y, ((row_gx, row_gy), row_mag))| {
                for x in 0..w {
                    let (gxv, gyv) = sobel_xy_at(luma, w, h, x, y);
                    row_gx[x] = gxv;
                    row_gy[x] = gyv;
                    row_mag[x] = (gxv * gxv + gyv * gyv).sqrt();
                }
            });
    }
    #[cfg(target_arch = "wasm32")]
    {
        for y in 0..h {
            for x in 0..w {
                let i = y * w + x;
                let (gxv, gyv) = sobel_xy_at(luma, w, h, x, y);
                gx[i] = gxv;
                gy[i] = gyv;
                mag[i] = (gxv * gxv + gyv * gyv).sqrt();
            }
        }
    }

    #[cfg(not(target_arch = "wasm32"))]
    {
        let mut mx = 1e-8_f32;
        for &m in &mag {
            mx = mx.max(m);
        }
        mag.par_iter_mut()
            .for_each(|m| *m = (*m / mx).clamp(0.0, 1.0));
    }
    #[cfg(target_arch = "wasm32")]
    {
        let mut mx = 1e-8_f32;
        for &m in &mag {
            mx = mx.max(m);
        }
        for m in mag.iter_mut() {
            *m = (*m / mx).clamp(0.0, 1.0);
        }
    }
    (gx, gy, mag)
}

fn normalize_minmax_inplace(v: &mut [f32]) {
    let mut lo = f32::INFINITY;
    let mut hi = f32::NEG_INFINITY;
    for &x in v.iter() {
        if x.is_finite() {
            lo = lo.min(x);
            hi = hi.max(x);
        }
    }
    let spread = hi - lo;
    if !spread.is_finite() || spread <= 1e-8 {
        for x in v.iter_mut() {
            *x = 0.5;
        }
        return;
    }
    for x in v.iter_mut() {
        *x = ((*x - lo) / spread).clamp(0.0, 1.0);
    }
}

/// Build fused `cue_prior` and summary stats for provenance / sieve blending.
pub fn build_monocular_cue_maps(
    rgb: &[f32],
    w: usize,
    h: usize,
) -> Result<MonocularCueMaps, DepthError> {
    if w == 0 || h == 0 {
        return Err(DepthError::Shape);
    }
    let n = w * h;
    let luma = luma_seq(rgb, w, h)?;
    let means = means_per_level(&luma, w, h)?;
    let (gx, gy, mut sobel_mag) = sobel_luma_mag(&luma, w, h);

    let mut band0 = vec![0.0_f32; n];
    let mut band1 = vec![0.0_f32; n];
    let mut band2 = vec![0.0_f32; n];
    let mut band3 = vec![0.0_f32; n];
    let mut low = vec![0.0_f32; n];
    for i in 0..n {
        band0[i] = (means[0][i] - means[1][i]).abs();
        band1[i] = (means[1][i] - means[2][i]).abs();
        band2[i] = (means[2][i] - means[3][i]).abs();
        band3[i] = (means[3][i] - means[4][i]).abs();
        low[i] = means[4][i].abs();
    }

    let mut level_mean = [0.0_f32; MONOCULAR_CUE_LEVELS];
    level_mean[0] = band0.iter().copied().sum::<f32>() / n as f32;
    level_mean[1] = band1.iter().copied().sum::<f32>() / n as f32;
    level_mean[2] = band2.iter().copied().sum::<f32>() / n as f32;
    level_mean[3] = band3.iter().copied().sum::<f32>() / n as f32;
    level_mean[4] = low.iter().copied().sum::<f32>() / n as f32;

    // Texture gradient proxy: fine bands vs coarse residual (near = more high-frequency energy).
    let mut texture = vec![0.0_f32; n];
    for i in 0..n {
        let fine = band0[i] + band1[i];
        let coarse = band3[i] + low[i] + 1e-4;
        texture[i] = (fine / coarse).clamp(0.0, 8.0).min(1.0);
    }
    normalize_minmax_inplace(&mut texture);

    // Aerial perspective proxy: cool shift + low saturation at coarse luma.
    let mut aerial = vec![0.0_f32; n];
    for i in 0..n {
        let o = i * 3;
        let r = rgb[o].clamp(0.0, 1.0);
        let g = rgb[o + 1].clamp(0.0, 1.0);
        let b = rgb[o + 2].clamp(0.0, 1.0);
        let mx = r.max(g).max(b);
        let mn = r.min(g).min(b);
        let sat = if mx <= 1e-6 {
            0.0
        } else {
            ((mx - mn) / mx).clamp(0.0, 1.0)
        };
        let cool = (b - r).clamp(-1.0, 1.0);
        let haze = (1.0 - sat) * 0.55 + (cool * 0.5 + 0.5) * 0.45;
        let coarse_l = means[4][i];
        aerial[i] = (haze * 0.65 + coarse_l * 0.35).clamp(0.0, 1.0);
    }
    normalize_minmax_inplace(&mut aerial);

    // Linear perspective proxy: dominance of horizontal structure in gradients (man-made lines).
    let mut persp = vec![0.0_f32; n];
    for i in 0..n {
        let h = gx[i].abs();
        let v = gy[i].abs();
        persp[i] = (h / (h + v + 1e-4)).clamp(0.0, 1.0);
    }
    normalize_minmax_inplace(&mut persp);

    // Occlusion / boundary support: strong luminance edges (T-junctions live in topology alpha too).
    normalize_minmax_inplace(&mut sobel_mag);

    let mut cue_prior = vec![0.0_f32; n];
    for i in 0..n {
        cue_prior[i] =
            (0.30 * texture[i] + 0.28 * aerial[i] + 0.22 * persp[i] + 0.20 * sobel_mag[i])
                .clamp(0.0, 1.0);
    }

    Ok(MonocularCueMaps {
        cue_prior,
        provenance: MonocularCueProvenance {
            level_band_energy_mean: level_mean,
            scale_ambiguity: "relative_ratio_scale_only; metric_depth_requires_anchor_prior".into(),
        },
    })
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn checkerboard_increases_finest_band_energy_vs_flat() {
        let w = 32_usize;
        let h = 32_usize;
        let n = w * h;
        let flat = vec![0.5_f32; n * 3];
        let mut chk = vec![0.5_f32; n * 3];
        for i in 0..n {
            let x = i % w;
            let y = i / w;
            let c = if (x ^ y) & 1 == 0 { 0.12 } else { 0.88 };
            chk[i * 3] = c;
            chk[i * 3 + 1] = c;
            chk[i * 3 + 2] = c;
        }
        let m_flat = build_monocular_cue_maps(&flat, w, h).unwrap();
        let m_chk = build_monocular_cue_maps(&chk, w, h).unwrap();
        assert!(
            m_chk.provenance.level_band_energy_mean[0]
                > m_flat.provenance.level_band_energy_mean[0],
            "checkerboard should increase finest dyadic band energy vs flat field"
        );
    }
}
